import React from 'react';

// Define exactamente qué datos tiene una sesión
export interface SesionDatos {
  id: string | number;
  titulo: string;
  hora: string;
  cliente: string;
  // Añade aquí los demás campos que utilices
}

interface DetallesSesionProps {
  sesion: SesionDatos | null; // Puede ser null si no hay ninguna seleccionada
  onClose: () => void;
}

export default function DetallesSesion({ sesion, onClose }: DetallesSesionProps) {
  if (!sesion) return null;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50">
      <div className="bg-white p-6 rounded-lg w-96">
        <h2 className="text-xl font-bold">{sesion.titulo}</h2>
        <p className="text-gray-600">{sesion.hora}</p>
        <p className="mt-2">Cliente: {sesion.cliente}</p>
        
        <button 
          onClick={onClose}
          className="mt-4 bg-red-500 text-white px-4 py-2 rounded"
        >
          Cerrar
        </button>
      </div>
    </div>
  );
}
